mapper.select:
SELECT
    MAX(sc.class_serial_number) AS maxClassSerialNumber
FROM
    sys_class sc
WHERE
    sc.school_id = #{schoolId}
  AND sc.sid = #{sid}
  AND sc.grade_group = #{gradeGroupId}
  AND sc.deleted = 0

SELECT
    COUNT(*) as count
FROM
    sys_class sc left join grade_group gg on sc.grade_group = gg.id
WHERE
    sc.school_id = #{schoolId}
  AND sc.class_name = #{className}
  AND sc.deleted = 0
  AND gg.deleted = 0
  AND gg.grade = #{gradeGroup}
  and sc.sid = #{sid}

SELECT
    COUNT(1) as count
FROM
    sys_class sc left join grade_group gg on sc.grade_group = gg.id
WHERE
    sc.school_id = #{schoolId}
  AND sc.deleted = 0
  AND sc.class_serial_number = #{classSerialNumber}
  AND gg.deleted = 0
  AND gg.grade = #{gradeGroup}
  and sc.sid = #{sid}

SELECT sc.id AS classId, gg.grade_group_name AS groupName, sc.class_name AS className, gg.id AS groupId, sc.department AS department FROM sys_class sc left join grade_group gg on sc.grade_group = gg.id WHERE sc.school_id = #{schoolId}
AND sc.sid = #{sid}
AND sc.deleted = 0
AND sc.department = #{department}

SELECT sc.id AS classId, sc.class_name AS className, gg.grade_group_name AS groupName, gg.grade AS grade, gg.id AS groupId, sc.department AS department FROM sys_class sc LEFT JOIN grade_group gg ON sc.grade_group = gg.id WHERE sc.deleted = 0 AND sc.school_id = #{schoolId}
AND sc.sid = #{schoolYear}
AND sc.grade_group = #{gradeGroupId}
AND sc.department = #{department}
AND sc.id IN
#{classId}
